Rules.InvariantScript:
Set(varLoading, true);

Set(
    varOrientacao,
    If(App.Width > App.Height, "Paisagem", "Retrato")
);


Set(varLoading, false)

ControlPropertyState.AutoRuleBindingString:
Set(varLoading, true);

Set(
    varDetalheAtual,
    {
        Tipo:       varServicoSelecionado.Tipo,
        HasServico: !IsBlank(varServicoSelecionado.Servico) && varServicoSelecionado.Tipo = "SERVICO",
        HasTroca:   !IsBlank(varServicoSelecionado.Troca)   && varServicoSelecionado.Tipo = "TROCA",
        HasManut:   !IsBlank(varServicoSelecionado.Manut)   && varServicoSelecionado.Tipo = "MANUTENCAO",
        Servico:    varServicoSelecionado.Servico,
        Troca:      varServicoSelecionado.Troca,
        Manut:      varServicoSelecionado.Manut,
        ManutGeral: varServicoSelecionado.ManutGeral
    }
);

Set(varLoading, false)

Rules.InvariantScript:
Navigate(TelaServiços, ScreenTransition.Fade);
Reset(PenInputPas); Reset(CampoKmInicialVOUCHER); Reset(CampoKmFinalVOUCHER);
    Reset(cmbHorarioInicialHoraVOUCHER); Reset(cmbHorarioInicialMinVOUCHER);
    Reset(cmbEsperaInicialHoraVOUCHER); Reset(cmbEsperaInicialMinVOUCHER);
    Reset(cmbEsperaFinalHoraVOUCHER); Reset(cmbEsperaFinalMinVOUCHER);
    Reset(CampoPedagioVOUCHER); Reset(CampoObsVOUCHER_1);
    Set(varAssPas, "");

// 1. Apaga rascunho no Dataverse
IfError(
    Patch(
        Geral,
        LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
        {'Rascunho Voucher': Blank()}
    ),
    Notify("❌ Erro ao limpar rascunho.", NotificationType.Error, 3000)
);

// 2. Zera varRascunho — Default dos campos agora retorna ""
Set(varRascunho, ParseJSON("{}"));

// 3. Reset dos campos (seu código original)
Reset(PenInputPas); Reset(CampoKmInicialVOUCHER); Reset(CampoKmFinalVOUCHER);
Reset(cmbHorarioInicialHoraVOUCHER); Reset(cmbHorarioInicialMinVOUCHER);
Reset(cmbEsperaInicialHoraVOUCHER); Reset(cmbEsperaInicialMinVOUCHER);
Reset(cmbEsperaFinalHoraVOUCHER); Reset(cmbEsperaFinalMinVOUCHER);
Reset(CampoPedagioVOUCHER); Reset(CampoObsVOUCHER_1);
Set(varAssPas, ""); Reset(CampoCombustivelVOUCHER_2); Reset(CampoDesvioVOUCHER);
Reset(CampoEstacionamentoVOUCHER_1); Reset(CampoHospedagemVOUCHER_3);
Reset(CampoOutrosVOUCHER_4); Reset(CampoPedagioVOUCHER);
Reset(PenInputPas);
Set(varAssinou, false)

With(
    {
        wMinServico: Hour(varDetalheAtual.Servico.'Data e horário de saída') * 60 +
                     Minute(varDetalheAtual.Servico.'Data e horário de saída'),
        wDiasOffset: DateDiff(
                         DateValue(Text(varDetalheAtual.Servico.'Data e horário de saída', "yyyy-mm-dd")),
                         Today(),
                         TimeUnit.Days
                     )
    },
    With(
        {
            wMinIniAbsoluto: wDiasOffset * 1440 +
                             Value(cmbHorarioInicialHoraVOUCHER.Selected.Value) * 60 +
                             Value(cmbHorarioInicialMinVOUCHER.Selected.Value)
        },
        If(
            !IsBlank(cmbHorarioInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbHorarioInicialMinVOUCHER.Selected) &&
            wMinServico - wMinIniAbsoluto > 15,

            // INVÁLIDO
            Notify(
                "⚠️ Horário inicial não pode ser mais de 15 min antes da saída do serviço (" &
                Text(Hour(varDetalheAtual.Servico.'Data e horário de saída'), "00") & ":" &
                Text(Minute(varDetalheAtual.Servico.'Data e horário de saída'), "00") & ").",
                NotificationType.Warning,
                3000
            );
            Reset(cmbHorarioInicialHoraVOUCHER),

            // VÁLIDO — salva
            IfError(
                Patch(
                    Geral,
                    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    {
                        'Rascunho Voucher': JSON({
                            km_inicial:      CampoKmInicialVOUCHER.Text,
                            km_final:        CampoKmFinalVOUCHER.Text,
                            hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                            min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                            espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                            espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                            espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                            espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                            desvio:          CampoDesvioVOUCHER.Value,
                            obs:             CampoObsVOUCHER_1.Value,
                            pedagio:         CampoPedagioVOUCHER.Text,
                            estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                            combustivel:     CampoCombustivelVOUCHER_2.Text,
                            hospedagem:      CampoHospedagemVOUCHER_3.Text,
                            outros:          CampoOutrosVOUCHER_4.Text
                        })
                    }
                ),
                Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
            );
            Set(
                varDetalheAtual,
                {
                    ManutGeral: varDetalheAtual.ManutGeral,
                    Manut:      varDetalheAtual.Manut,
                    Servico:    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    Troca:      varDetalheAtual.Troca,
                    Tipo:       "SERVICO"
                }
            );
            Set(varRascunho, ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher'))
        )
    )
)

With(
    {
        wMinServico: Hour(varDetalheAtual.Servico.'Data e horário de saída') * 60 +
                     Minute(varDetalheAtual.Servico.'Data e horário de saída'),
        wDiasOffset: DateDiff(
                         DateValue(Text(varDetalheAtual.Servico.'Data e horário de saída', "yyyy-mm-dd")),
                         Today(),
                         TimeUnit.Days
                     )
    },
    With(
        {
            wMinIniAbsoluto: wDiasOffset * 1440 +
                             Value(cmbHorarioInicialHoraVOUCHER.Selected.Value) * 60 +
