        },
        If(
            !IsBlank(cmbHorarioInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbHorarioInicialMinVOUCHER.Selected) &&
            wMinServico - wMinIniAbsoluto > 15,

            Notify(
                "⚠️ Horário inicial não pode ser mais de 15 min antes da saída do serviço (" &
                Text(Hour(varDetalheAtual.Servico.'Data e horário de saída'), "00") & ":" &
                Text(Minute(varDetalheAtual.Servico.'Data e horário de saída'), "00") & ").",
                NotificationType.Warning,
                3000
            );
            Reset(cmbHorarioInicialMinVOUCHER),

            IfError(
                Patch(
                    Geral,
                    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    {
                        'Rascunho Voucher': JSON({
                            km_inicial:      CampoKmInicialVOUCHER.Text,
                            km_final:        CampoKmFinalVOUCHER.Text,
                            hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                            min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                            espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                            espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                            espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                            espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                            desvio:          CampoDesvioVOUCHER.Value,
                            obs:             CampoObsVOUCHER_1.Value,
                            pedagio:         CampoPedagioVOUCHER.Text,
                            estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                            combustivel:     CampoCombustivelVOUCHER_2.Text,
                            hospedagem:      CampoHospedagemVOUCHER_3.Text,
                            outros:          CampoOutrosVOUCHER_4.Text
                        })
                    }
                ),
                Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
            );
            Set(
                varDetalheAtual,
                {
                    ManutGeral: varDetalheAtual.ManutGeral,
                    Manut:      varDetalheAtual.Manut,
                    Servico:    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    Troca:      varDetalheAtual.Troca,
                    Tipo:       "SERVICO"
                }
            );
            Set(varRascunho, ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher'))
        )
    )
)

With(
    {
        wMinIniRaw:    Value(cmbHorarioInicialHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbHorarioInicialMinVOUCHER.Selected.Value),
        wMinEspIniRaw: Value(cmbEsperaInicialHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbEsperaInicialMinVOUCHER.Selected.Value)
    },
    With(
        {
            // Threshold -720: diferença < -12h → cruzou meia-noite → ajusta +1440
            wMinEspIniAjustado: If(
                wMinEspIniRaw - wMinIniRaw < -720,
                wMinEspIniRaw + 1440,
                wMinEspIniRaw
            )
        },
        If(
            !IsBlank(cmbHorarioInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbHorarioInicialMinVOUCHER.Selected) &&
            !IsBlank(cmbEsperaInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbEsperaInicialMinVOUCHER.Selected) &&
            wMinEspIniAjustado <= wMinIniRaw,

            Notify(
                "⚠️ O início da espera deve ser posterior ao horário inicial do voucher.",
                NotificationType.Warning,
                3000
            );
            Reset(cmbEsperaInicialHoraVOUCHER),

            IfError(
                Patch(
                    Geral,
                    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    {
                        'Rascunho Voucher': JSON({
                            km_inicial:      CampoKmInicialVOUCHER.Text,
                            km_final:        CampoKmFinalVOUCHER.Text,
                            hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                            min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                            espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                            espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                            espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                            espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                            desvio:          CampoDesvioVOUCHER.Value,
                            obs:             CampoObsVOUCHER_1.Value,
                            pedagio:         CampoPedagioVOUCHER.Text,
                            estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                            combustivel:     CampoCombustivelVOUCHER_2.Text,
                            hospedagem:      CampoHospedagemVOUCHER_3.Text,
                            outros:          CampoOutrosVOUCHER_4.Text
                        })
                    }
                ),
                Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
            );
            Set(
                varDetalheAtual,
                {
                    ManutGeral: varDetalheAtual.ManutGeral,
                    Manut:      varDetalheAtual.Manut,
                    Servico:    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    Troca:      varDetalheAtual.Troca,
                    Tipo:       "SERVICO"
                }
            );
            Set(varRascunho, ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher'))
        )
    )
)

With(
    {
        wMinIniRaw:    Value(cmbHorarioInicialHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbHorarioInicialMinVOUCHER.Selected.Value),
        wMinEspIniRaw: Value(cmbEsperaInicialHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbEsperaInicialMinVOUCHER.Selected.Value)
    },
    With(
        {
            wMinEspIniAjustado: If(
                wMinEspIniRaw - wMinIniRaw < -720,
                wMinEspIniRaw + 1440,
                wMinEspIniRaw
            )
        },
        If(
            !IsBlank(cmbHorarioInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbHorarioInicialMinVOUCHER.Selected) &&
            !IsBlank(cmbEsperaInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbEsperaInicialMinVOUCHER.Selected) &&
            wMinEspIniAjustado <= wMinIniRaw,

            Notify(
                "⚠️ O início da espera deve ser posterior ao horário inicial do voucher.",
                NotificationType.Warning,
                3000
            );
            Reset(cmbEsperaInicialMinVOUCHER),

            IfError(
                Patch(
                    Geral,
                    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    {
                        'Rascunho Voucher': JSON({
                            km_inicial:      CampoKmInicialVOUCHER.Text,
                            km_final:        CampoKmFinalVOUCHER.Text,
                            hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                            min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                            espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                            espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                            espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                            espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                            desvio:          CampoDesvioVOUCHER.Value,
                            obs:             CampoObsVOUCHER_1.Value,
                            pedagio:         CampoPedagioVOUCHER.Text,
                            estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                            combustivel:     CampoCombustivelVOUCHER_2.Text,
                            hospedagem:      CampoHospedagemVOUCHER_3.Text,
                            outros:          CampoOutrosVOUCHER_4.Text
                        })
                    }
                ),
                Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
            );
            Set(
                varDetalheAtual,
                {
                    ManutGeral: varDetalheAtual.ManutGeral,
                    Manut:      varDetalheAtual.Manut,
                    Servico:    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    Troca:      varDetalheAtual.Troca,
                    Tipo:       "SERVICO"
                }
            );
            Set(varRascunho, ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher'))
        )
    )
)

With(
    {
        wDiasOffset:   DateDiff(
                           DateValue(Text(varDetalheAtual.Servico.'Data e horário de saída', "yyyy-mm-dd")),
                           Today(),
                           TimeUnit.Days
                       ),
        wMinAgora:     Hour(Now()) * 60 + Minute(Now()),
        wMinEspIniRaw: Value(cmbEsperaInicialHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbEsperaInicialMinVOUCHER.Selected.Value),
        wMinEspFimRaw: Value(cmbEsperaFinalHoraVOUCHER.Selected.Value) * 60 +
                       Value(cmbEsperaFinalMinVOUCHER.Selected.Value)
    },
    With(
        {
            wMinEspFimAjustado: If(
                wMinEspFimRaw - wMinEspIniRaw < -720,
                wMinEspFimRaw + 1440,
                wMinEspFimRaw
            )
        },
        If(
            // 1. Futuro — só valida se preenchendo no mesmo dia do serviço
            !IsBlank(cmbEsperaFinalHoraVOUCHER.Selected) &&
            !IsBlank(cmbEsperaFinalMinVOUCHER.Selected) &&
            wDiasOffset = 0 &&
            wMinEspFimRaw > wMinAgora,

            Notify("⚠️ O horário final da espera não pode ser futuro.", NotificationType.Warning, 3000);
            Reset(cmbEsperaFinalHoraVOUCHER),

            // 2. Ordem — fim deve ser após início da espera
            !IsBlank(cmbEsperaInicialHoraVOUCHER.Selected) &&
            !IsBlank(cmbEsperaInicialMinVOUCHER.Selected) &&
            !IsBlank(cmbEsperaFinalHoraVOUCHER.Selected) &&
            !IsBlank(cmbEsperaFinalMinVOUCHER.Selected) &&
            wMinEspFimAjustado <= wMinEspIniRaw,

            Notify("⚠️ O fim da espera deve ser posterior ao início.", NotificationType.Warning, 3000);
            Reset(cmbEsperaFinalHoraVOUCHER),

            // VÁLIDO — salva
            IfError(
                Patch(
                    Geral,
                    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    {
                        'Rascunho Voucher': JSON({
                            km_inicial:      CampoKmInicialVOUCHER.Text,
                            km_final:        CampoKmFinalVOUCHER.Text,
                            hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                            min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                            espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                            espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                            espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                            espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                            desvio:          CampoDesvioVOUCHER.Value,
                            obs:             CampoObsVOUCHER_1.Value,
                            pedagio:         CampoPedagioVOUCHER.Text,
                            estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                            combustivel:     CampoCombustivelVOUCHER_2.Text,
                            hospedagem:      CampoHospedagemVOUCHER_3.Text,
                            outros:          CampoOutrosVOUCHER_4.Text
                        })
                    }
                ),
                Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
            );
            Set(
                varDetalheAtual,
                {
                    ManutGeral: varDetalheAtual.ManutGeral,
                    Manut:      varDetalheAtual.Manut,
                    Servico:    LookUp(Geral, 'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'),
                    Troca:      varDetalheAtual.Troca,
                    Tipo:       "SERVICO"
                }
            );
            Set(varRascunho, ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher'))
        )
    )
)

IfError(
    Patch(
        Geral,
        LookUp(
            Geral,
            'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'
        ),
        {
            'Rascunho Voucher': JSON(
                {
                    km_inicial:      CampoKmInicialVOUCHER.Text,
                    km_final:        CampoKmFinalVOUCHER.Text,
                    hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                    min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                    espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                    espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                    espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                    espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                    desvio:          CampoDesvioVOUCHER.Value,
                    obs:             CampoObsVOUCHER_1.Value,
                    pedagio:         CampoPedagioVOUCHER.Text,
                    estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                    combustivel:     CampoCombustivelVOUCHER_2.Text,
                    hospedagem:      CampoHospedagemVOUCHER_3.Text,
                    outros:          CampoOutrosVOUCHER_4.Text
                }
            )
        }
    ),
    Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
);
Set(
    varDetalheAtual,
    {
        ManutGeral: varDetalheAtual.ManutGeral,
        Manut:      varDetalheAtual.Manut,
        Servico:    LookUp(
                        Geral,
                        'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'
                    ),
        Troca:      varDetalheAtual.Troca,
        Tipo: "SERVICO"
    }
);
Set(
    varRascunho,
    ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher')
)

If(
    !IsMatch(Self.Text, "^\d+$"),
    Notify("⚠️ O KM Inicial deve ser um número inteiro (sem vírgulas ou pontos).", NotificationType.Warning, 3000);
    Reset(Self)
);
IfError(
    Patch(
        Geral,
        LookUp(
            Geral,
            'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'
        ),
        {
            'Rascunho Voucher': JSON(
                {
                    km_inicial:      CampoKmInicialVOUCHER.Text,
                    km_final:        CampoKmFinalVOUCHER.Text,
                    hora_saida:      cmbHorarioInicialHoraVOUCHER.Selected.Value,
                    min_saida:       cmbHorarioInicialMinVOUCHER.Selected.Value,
                    espera_ini_hora: cmbEsperaInicialHoraVOUCHER.Selected.Value,
                    espera_ini_min:  cmbEsperaInicialMinVOUCHER.Selected.Value,
                    espera_fim_hora: cmbEsperaFinalHoraVOUCHER.Selected.Value,
                    espera_fim_min:  cmbEsperaFinalMinVOUCHER.Selected.Value,
                    desvio:          CampoDesvioVOUCHER.Value,
                    obs:             CampoObsVOUCHER_1.Value,
                    pedagio:         CampoPedagioVOUCHER.Text,
                    estacionamento:  CampoEstacionamentoVOUCHER_1.Text,
                    combustivel:     CampoCombustivelVOUCHER_2.Text,
                    hospedagem:      CampoHospedagemVOUCHER_3.Text,
                    outros:          CampoOutrosVOUCHER_4.Text
                }
            )
        }
    ),
    Notify("❌ Erro ao salvar rascunho. Tente novamente.", NotificationType.Error, 3000)
);
Set(
    varDetalheAtual,
    {
        ManutGeral: varDetalheAtual.ManutGeral,
        Manut:      varDetalheAtual.Manut,
        Servico:    LookUp(
                        Geral,
                        'GUID Reserva de Veículos' = varDetalheAtual.Servico.'GUID Reserva de Veículos'
                    ),
        Troca:      varDetalheAtual.Troca,
        Tipo: "SERVICO"
    }
);
Set(
    varRascunho,
    ParseJSON(varDetalheAtual.Servico.'Rascunho Voucher')
)

If(
    // 1) Valida se é um número inteiro positivo
    !IsMatch(Self.Text, "^\d+$"),
    Reset(Self);
    Notify(
        "⚠️ O KM deve ser um número inteiro (sem vírgulas ou pontos).",
        NotificationType.Warning,
        3000
