If(
    varLoading,
    false,

    Set(varLoading, true);

    // ── 1. Variáveis locais ──────────────────────────────────────────
    Set(_guidSrv, varDetalheAtual.Servico.'GUID Reserva de Veículos');

    // Primeiro item PENDENTE da fila única (ignora HEADERs e já concluídos)
    Set(
    _proxItem,
    First(
        SortByColumns(
            Filter(
                colAgendaUI,
                !IsBlank(DtOrdem) &&
                Tipo <> "HEADER" &&
                !(Tipo = "SERVICO"    && !IsBlank(DadosSERVICO)    && ("conclu" in Lower(Text(DadosSERVICO.'Status de Operação'))    || "cancel" in Lower(Text(DadosSERVICO.'Status de Operação')))) &&
                !(Tipo = "TROCA"      && !IsBlank(DadosTROCA)      && ("conclu" in Lower(Text(DadosTROCA.'Status (cr40f_statusdatroca)'))          || "cancel" in Lower(Text(DadosTROCA.'Status (cr40f_statusdatroca)')))) &&
                !(Tipo = "MANUTENCAO" && !IsBlank(DadosMANUTENCAO) && ("realizado" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)')) || "conclu" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)')) || "cancel" in Lower(Text(DadosMANUTENCAO.'Status (cr40f_status)'))))
            ),
            "DtOrdem",
            SortOrder.Ascending
        )
    )
);

    // ── 2. Validação: GUID existe ────────────────────────────────────
    If(
        IsBlank(_guidSrv),
        Notify("Não foi possível identificar o serviço.", NotificationType.Error, 4000);
        Set(varLoading, false),

        // ── 3. Validação: fila não está vazia ────────────────────────
        If(
            IsBlank(_proxItem),
            Notify("Nenhum item pendente encontrado na fila.", NotificationType.Error, 4000);
            Set(varLoading, false),

            // ── 4. Validação: este serviço é o primeiro pendente ─────
            If(
                !(_proxItem.Tipo = "SERVICO" &&
                  _proxItem.DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv),
                Notify(
                    "⚠️ Conclua os itens anteriores da fila antes de prosseguir.",
                    NotificationType.Warning,
                    4000
                );
                Set(varLoading, false),

                // ── 5. Validação: ainda não concluído ─────────────────
                If(
                    varDetalheAtual.Servico.'Status de Operação' = 'Status de Operação'.Concluído,
                    Notify("Este serviço já foi concluído.", NotificationType.Information, 4000);
                    Set(varLoading, false),

                    // ── 6. Busca no banco ─────────────────────────────
                    With(
                        { srvDb: LookUp(Geral, 'GUID Reserva de Veículos' = _guidSrv) },

                        If(
                            IsBlank(srvDb),
                            Notify("Serviço não encontrado. Atualize a página.", NotificationType.Error, 4000);
                            Set(varLoading, false),

                            // ── 7. Patch + atualização local ──────────
                            IfError(
                                With(
                                    {
                                        srvAtualizado: Patch(
                                            Geral,
                                            srvDb,
                                            { 'Status de Operação': 'Status de Operação'.Concluído }
                                        )
                                    },

                                    // Atualiza varDetalheAtual em memória
                                    Set(varDetalheAtual, { Servico: srvAtualizado });

                                    // Atualiza colAgenda
                                    With(
                                        {
                                            recAgenda: LookUp(
                                                colAgenda,
                                                Tipo = "SERVICO" &&
                                                !IsBlank(DadosSERVICO) &&
                                                DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgenda),
                                            Patch(colAgenda, recAgenda, { DadosSERVICO: srvAtualizado })
                                        )
                                    );

                                    // Atualiza colAgendaUI
                                    With(
                                        {
                                            recAgendaUI: LookUp(
                                                colAgendaUI,
                                                Tipo = "SERVICO" &&
                                                !IsBlank(DadosSERVICO) &&
                                                DadosSERVICO.'GUID Reserva de Veículos' = _guidSrv
                                            )
                                        },
                                        If(
                                            !IsBlank(recAgendaUI),
                                            Patch(colAgendaUI, recAgendaUI, { DadosSERVICO: srvAtualizado })
                                        )
                                    );

                                    Notify("✅ Serviço concluído com sucesso!", NotificationType.Success, 3000);
                                    Set(varLoading, false);
                                    Navigate(TelaServiços, ScreenTransition.Fade)
                                ),

                                // Erro no Patch
                                Notify(
                                    "❌ Falha ao concluir. Verifique sua conexão e tente novamente.",
                                    NotificationType.Error,
                                    5000
                                );
                                Set(varLoading, false)
                            )
                        )
                    )
                )
            )
        )
    )
)

