Set(_kmIn,  Text(Value(CampoKmInicialVOUCHER.Text),  "0"));
Set(_kmFi,  Text(Value(CampoKmFinalVOUCHER.Text),    "0"));
Set(_hIni,
    If(
        IsBlank(cmbHorarioInicialHoraVOUCHER.Selected) || IsBlank(cmbHorarioInicialMinVOUCHER.Selected),
        "",
        Text(cmbHorarioInicialHoraVOUCHER.Selected.Value) & ":" & Right("00" & Text(cmbHorarioInicialMinVOUCHER.Selected.Value), 2)
    )
);
Set(_hEspIni,
    If(
        IsBlank(cmbEsperaInicialHoraVOUCHER.Selected) || IsBlank(cmbEsperaInicialMinVOUCHER.Selected),
        "",
        Text(cmbEsperaInicialHoraVOUCHER.Selected.Value) & ":" & Right("00" & Text(cmbEsperaInicialMinVOUCHER.Selected.Value), 2)
    )
);
Set(_hEspFim,
    If(
        IsBlank(cmbEsperaFinalHoraVOUCHER.Selected) || IsBlank(cmbEsperaFinalMinVOUCHER.Selected),
        "",
        Text(cmbEsperaFinalHoraVOUCHER.Selected.Value) & ":" & Right("00" & Text(cmbEsperaFinalMinVOUCHER.Selected.Value), 2)
    )
);
Set(_vPed, Text(Round(Value(Substitute(CampoPedagioVOUCHER.Text,        "R$", "")), 2), "0.00", "en-US"));
Set(_vEst, Text(Round(Value(Substitute(CampoEstacionamentoVOUCHER_1.Text, "R$", "")), 2), "0.00", "en-US"));
Set(_vCom, Text(Round(Value(Substitute(CampoCombustivelVOUCHER_2.Text,  "R$", "")), 2), "0.00", "en-US"));
Set(_vHos, Text(Round(Value(Substitute(CampoHospedagemVOUCHER_3.Text,  "R$", "")), 2), "0.00", "en-US"));
Set(_vOut, Text(Round(Value(Substitute(CampoOutrosVOUCHER_4.Text,       "R$", "")), 2), "0.00", "en-US"));
Set(_obs,  CampoObsVOUCHER_1.Value);

// 3) VALIDAÇÕES — TODAS DE UMA VEZ (acumula erros)
Set(_erros, "");
If(IsBlank(_guidSrv),
    Set(_erros, _erros & "• Serviço não localizado." & Char(10));
    Set(_ok, false)
);
If(Value(_kmIn) = 0,
    Set(_erros, _erros & "• KM Inicial é obrigatório." & Char(10));
    Set(_ok, false)
);
If(Value(_kmFi) = 0,
    Set(_erros, _erros & "• KM Final é obrigatório." & Char(10));
    Set(_ok, false)
);
If(Value(_kmFi) <= Value(_kmIn) && Value(_kmFi) > 0 && Value(_kmIn) > 0,
    Set(_erros, _erros & "• KM Final deve ser maior que o Inicial." & Char(10));
    Set(_ok, false)
);
If(IsBlank(_hIni),
    Set(_erros, _erros & "• Horário de saída é obrigatório." & Char(10));
    Set(_ok, false)
);

If(
    !_ok,
    Notify("⚠️ Corrija antes de continuar:" & Char(10) & _erros, NotificationType.Error, 6000);
    Set(varLoading, false)
);

// 4) AVISO SEM BLOQUEIO — assinatura ausente
If(
    _ok && !varAssinou,
    Notify("📋 Prosseguindo sem assinatura. O responsável será notificado por e-mail.", NotificationType.Warning, 4000)
);

// 5) CHAMADA DO FLOW
If(
    _ok,
    Set(varStatusMsg, "📄 Gerando voucher...");
    Set(_flowResult,
        IfError(
            FlowGerarVoucherAppMotoristas.Run(
                _guidSrv,
                varAssPas,
                CampoDesvioVOUCHER.Value,
                _kmIn,
                _kmFi,
                _hIni,
                _hEspIni,
                _hEspFim,
                _vPed,
                _vEst,
                _vCom,
                _vHos,
                _vOut,
                _obs,
                Text(varHorarioFinal, "hh:mm"),
                varHorarioFinal
            ),
            Blank()
        )
    );
    If(
        IsBlank(_flowResult),
        Notify("❌ Falha na geração do voucher. Verifique sua conexão e tente novamente. Se o problema persistir, acione o suporte.", NotificationType.Error, 7000);
        Set(_ok, false);
        Set(varLoading, false)
    )
);

// 6) FINALIZAÇÃO
If(
    _ok,
    Set(varStatusMsg, "💾 Finalizando serviço...");
    IfError(
        Patch(
            Geral,
            LookUp(Geral, 'GUID Reserva de Veículos' = _guidSrv),
            {
                'Status de Operação': 'Status de Operação'.Concluído,
                'Rascunho Voucher':   Blank(),
                'Data de Finalização': Now()
            }
        ),
        Notify("⚠️ Voucher gerado, mas houve erro ao atualizar o status. Avise o suporte.", NotificationType.Warning, 6000)
    );

    Set(varAssinou, false);
    Set(varAssPas,  "");
    Set(varStatusMsg, "");

    Reset(PenInputPas);
    Reset(CampoKmInicialVOUCHER); Reset(CampoKmFinalVOUCHER);
    Reset(cmbHorarioInicialHoraVOUCHER); Reset(cmbHorarioInicialMinVOUCHER);
    Reset(cmbEsperaInicialHoraVOUCHER); Reset(cmbEsperaInicialMinVOUCHER);
    Reset(cmbEsperaFinalHoraVOUCHER); Reset(cmbEsperaFinalMinVOUCHER);
    Reset(CampoPedagioVOUCHER); Reset(CampoObsVOUCHER_1);
    Reset(CampoCombustivelVOUCHER_2); Reset(CampoDesvioVOUCHER);
    Reset(CampoEstacionamentoVOUCHER_1); Reset(CampoHospedagemVOUCHER_3);
    Reset(CampoOutrosVOUCHER_4);

    Notify("✅ Voucher gerado e serviço concluído com sucesso!", NotificationType.Success, 4000);
    Navigate(TelaFinalizar, ScreenTransition.Fade)
);

Set(varLoading, false)

