// 1) BLOQUEIO DE CONCORRÊNCIA
If(varLoading, Notify("⏳ Processamento em andamento.", NotificationType.Warning, 3000); false);

Set(varLoading, true);
Set(_ok, true);

// 2) SANITIZAÇÃO E CAPTURA BÁSICA
