Set(_hEspIni, If(IsBlank(cmbEsperaInicialHoraVOUCHER.Selected) || IsBlank(cmbEsperaInicialMinVOUCHER.Selected), "", Text(cmbEsperaInicialHoraVOUCHER.Selected.Value) & ":" & Right("00" & Text(cmbEsperaInicialMinVOUCHER.Selected.Value), 2)));
